import { useEffect, useState } from "react";
import {
  getUsers,
  createEmployee,
  updateUser,
  blockUser,
  deleteEmployee,
} from "../../api/adminApi";
import DashboardLayout from "../../components/layout/DashboardLayout";
import ErrorModal from "../../components/ErrorModal";
import { Pencil, Plus, ShieldOff, Trash2 } from "lucide-react";
import "../../styles/";

export default function UsersPage() {
  const [users, setUsers] = useState([]);
  const [filters, setFilters] = useState({ role: "", status: "" });

  const [formOpen, setFormOpen] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    fullName: "",
    phone: "",
    roleName: "COURIER",
  });

  const [errorModal, setErrorModal] = useState({ isOpen: false, message: "" });

  useEffect(() => {
    loadUsers();
  }, [filters]);

  const loadUsers = async () => {
    const params = {};
    if (filters.role) params.roleName = filters.role;
    if (filters.status) params.statusName = filters.status;

    const data = await getUsers(params);
    setUsers(data.content || []);
  };

  const openCreate = () => {
    setEditMode(false);
    setFormData({ email: "", password: "", fullName: "", phone: "", roleName: "COURIER" });
    setFormOpen(true);
  };

  const openEdit = (user) => {
    setEditMode(true);
    setSelectedUser(user);
    setFormData({
      email: user.email,
      fullName: user.fullName,
      phone: user.phone,
      roleName: user.role,
    });
    setFormOpen(true);
  };

  const handleSubmit = async () => {
    try {
      if (editMode) {
        await updateUser(selectedUser.id, formData);
      } else {
        await createEmployee(formData);
      }
      setFormOpen(false);
      loadUsers();
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  return (
    <DashboardLayout>
      <div className="users-page">

        <div className="header">
          <h2>Управление пользователями</h2>
          <button onClick={openCreate} className="add-btn">
            <Plus size={16}/> Добавить
          </button>
        </div>

        {/* Filters */}
        <div className="filters">
          <select onChange={(e) => setFilters({ ...filters, role: e.target.value })}>
            <option value="">Все роли</option>
            <option value="ADMIN">ADMIN</option>
            <option value="LOGIST">LOGIST</option>
            <option value="COURIER">COURIER</option>
          </select>

          <select onChange={(e) => setFilters({ ...filters, status: e.target.value })}>
            <option value="">Все статусы</option>
            <option value="Активен">Активен</option>
            <option value="Заблокирован">Заблокирован</option>
          </select>
        </div>

        {/* Table */}
        <div className="table-wrapper">
          <table className="users-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Email</th>
                <th>Имя</th>
                <th>Роль</th>
                <th>Статус</th>
                <th>Действия</th>
              </tr>
            </thead>

            <tbody>
              {users.map((u) => (
                <tr key={u.id}>
                  <td>{u.id}</td>
                  <td>{u.email}</td>
                  <td>{u.fullName}</td>
                  <td>{u.role}</td>
                  <td>
                    <span className={`status ${u.status === "Активен" ? "active" : "blocked"}`}>
                      {u.status}
                    </span>
                  </td>

                  <td className="actions">
                    <button onClick={() => openEdit(u)}>
                      <Pencil size={14}/>
                    </button>

                    <button onClick={() => blockUser(u.id, u.status === "Активен")}>
                      <ShieldOff size={14}/>
                    </button>

                    <button onClick={() => deleteEmployee(u.id)}>
                      <Trash2 size={14}/>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Modal */}
        {formOpen && (
          <div className="modal-overlay">
            <div className="modern-modal">
              <h3 className="modal-title">
                {editMode ? "Редактирование" : "Создание"}
              </h3>

              <input
                className="input"
                placeholder="Email"
                value={formData.email}
                onChange={(e)=>setFormData({...formData,email:e.target.value})}
              />

              {!editMode && (
                <input
                  type="password"
                  className="input"
                  placeholder="Пароль"
                  onChange={(e)=>setFormData({...formData,password:e.target.value})}
                />
              )}

              <input
                className="input"
                placeholder="Имя"
                value={formData.fullName}
                onChange={(e)=>setFormData({...formData,fullName:e.target.value})}
              />

              <input
                className="input"
                placeholder="Телефон"
                value={formData.phone}
                onChange={(e)=>setFormData({...formData,phone:e.target.value})}
              />

              <select
                className="input"
                value={formData.roleName}
                onChange={(e)=>setFormData({...formData,roleName:e.target.value})}
              >
                <option value="COURIER">COURIER</option>
                <option value="LOGIST">LOGIST</option>
                <option value="ADMIN">ADMIN</option>
              </select>

              <div className="modal-actions">
                <button onClick={()=>setFormOpen(false)}>Отмена</button>
                <button onClick={handleSubmit} className="save-btn">
                  Сохранить
                </button>
              </div>
            </div>
          </div>
        )}

        <ErrorModal
          isOpen={errorModal.isOpen}
          title="Ошибка"
          message={errorModal.message}
          onClose={() => setErrorModal({ isOpen: false, message: "" })}
        />

      </div>
    </DashboardLayout>
  );
}
